# ANTI-PATTERN: Direct coupling, no task specialization
class MonolithicBatter:
    def execute(self, ball_data):
        # Doing everything in one agent - decision, footwork, shot selection
        if ball_data['line'] == 'leg_stump':
            return self.analyze_field() + self.calculate_shot() + self.execute_stroke()
        # Impossible to reuse, test, or scale

# BEST PRACTICE: Supervisor pattern with specialized agents
class CricketSupervisor:
    def __init__(self):
        self.batter_agent = BatterAgent(role='stroke_selection')
        self.fielder_agent = FielderAgent(role='positioning')
        self.bowler_agent = BowlerAgent(role='delivery_planning')

    def orchestrate_over(self, match_state):
        batter_decision = self.batter_agent.decide(match_state)
        field_position = self.fielder_agent.analyze(batter_decision)
        bowl_strategy = self.bowler_agent.plan(field_position, match_state)
        return self.execute_play(batter_decision, field_position, bowl_strategy)

# BEST PRACTICE: Chain pattern for sequential deliveries
class BowlingChain:
    def __init__(self):
        self.agents = [
            AnalysisAgent(),      # Step 1: Analyze batsman
            DeliveryAgent(),      # Step 2: Plan delivery
            ExecutionAgent()      # Step 3: Execute with feedback
        ]

    def process_over(self, innings_context):
        context = innings_context
        for agent in self.agents:
            context = agent.execute(context)  # Each feeds next
        return context['final_result']

# BEST PRACTICE: Mesh pattern for fielder communication
class MeshFielders:
    def __init__(self, fielders):
        self.fielders = {f.name: f for f in fielders}
        self.ball_position = None

    def ball_played(self, ball_location):
        self.ball_position = ball_location
        # Each fielder directly communicates best coverage
        optimal_coverage = max(
            (f.calculate_intercept(ball_location) for f in self.fielders.values()),
            key=lambda x: x['success_probability']
        )
        return optimal_coverage
